 1	import * as React from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { Alert, AlertVariant, FormGroup, Stack, StackItem } from '@patternfly/react-core';
 5	
 6	type SupportedVolumesAlertProps = {
 7	  isVMRunning?: boolean;
 8	};
 9	
10	const SupportedVolumesAlert: React.FC<SupportedVolumesAlertProps> = ({ isVMRunning }) => {
11	  const { t } = useKubevirtTranslation();
12	
13	  if (!isVMRunning) {
14	    return null;
15	  }
16	  return (
17	    <FormGroup fieldId="snapshot-info-alerts">
18	      <Alert
19	        title={
20	          <Stack hasGutter>
21	            <StackItem>{t('Taking snapshot of running VirtualMachine.')}</StackItem>
22	          </Stack>
23	        }
24	        isInline
25	        variant={AlertVariant.info}
26	      />
27	    </FormGroup>
28	  );
29	};
30	
31	export default SupportedVolumesAlert;

